import{_ as o,o as a,c as t,ae as l}from"./chunks/framework.C7FLYIpo.js";const p=JSON.parse('{"title":"대시보드","description":"게이트웨이 대시보드 (Control UI) 액세스 및 인증","frontmatter":{"title":"대시보드","description":"게이트웨이 대시보드 (Control UI) 액세스 및 인증"},"headers":[],"relativePath":"web/dashboard.md","filePath":"web/dashboard.md","lastUpdated":null}'),c={name:"web/dashboard.md"};function r(d,e,i,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="대시보드-control-ui" tabindex="-1">대시보드 (Control UI) <a class="header-anchor" href="#대시보드-control-ui" aria-label="Permalink to &quot;대시보드 (Control UI)&quot;">​</a></h1><p>게이트웨이 대시보드는 기본적으로 <code>/</code>에서 제공되는 브라우저 Control UI입니다 (<code>gateway.controlUi.basePath</code>로 재정의).</p><p>빠른 열기 (로컬 게이트웨이):</p><ul><li><a href="http://127.0.0.1:18789/" target="_blank" rel="noreferrer">http://127.0.0.1:18789/</a> (또는 <a href="http://localhost:18789/" target="_blank" rel="noreferrer">http://localhost:18789/</a>)</li></ul><p>주요 참조:</p><ul><li><a href="/openclaw-docs-ko/web/control-ui">Control UI</a> — 사용법 및 UI 기능.</li><li><a href="/openclaw-docs-ko/gateway/tailscale">Tailscale</a> — Serve/Funnel 자동화.</li><li><a href="/openclaw-docs-ko/web">웹 인터페이스</a> — 바인드 모드 및 보안 참고 사항.</li></ul><p>인증은 구성된 게이트웨이 인증 경로를 통해 WebSocket 핸드셰이크에서 시행됩니다:</p><ul><li><code>connect.params.auth.token</code></li><li><code>connect.params.auth.password</code></li><li><code>gateway.auth.allowTailscale: true</code>인 경우 Tailscale Serve 아이덴티티 헤더</li><li><code>gateway.auth.mode: &quot;trusted-proxy&quot;</code>인 경우 trusted-proxy 아이덴티티 헤더</li></ul><p><a href="/openclaw-docs-ko/gateway/configuration">게이트웨이 구성</a>에서 <code>gateway.auth</code>를 참조하십시오.</p><p>보안 참고: Control UI는 <strong>관리자 인터페이스</strong> (채팅, 구성, exec 승인)입니다. 공개적으로 노출하지 마십시오. UI는 현재 브라우저 탭 세션과 선택된 게이트웨이 URL에 대한 대시보드 URL 토큰을 sessionStorage에 유지하고 로드 후 URL에서 제거합니다. localhost, Tailscale Serve, 또는 SSH 터널을 사용하는 것이 좋습니다.</p><h2 id="빠른-경로-권장" tabindex="-1">빠른 경로 (권장) <a class="header-anchor" href="#빠른-경로-권장" aria-label="Permalink to &quot;빠른 경로 (권장)&quot;">​</a></h2><ul><li>온보딩 후 CLI는 자동으로 대시보드를 열고 깔끔한 (토큰화되지 않은) 링크를 출력합니다.</li><li>언제든지 다시 열기: <code>openclaw dashboard</code> (링크 복사, 가능하면 브라우저 열기, 헤드리스인 경우 SSH 힌트 표시).</li><li>UI에서 공유 비밀 인증을 요청하면 구성된 토큰 또는 비밀번호를 Control UI 설정에 붙여넣으십시오.</li></ul><h2 id="인증-기본-사항-로컬-vs-원격" tabindex="-1">인증 기본 사항 (로컬 vs 원격) <a class="header-anchor" href="#인증-기본-사항-로컬-vs-원격" aria-label="Permalink to &quot;인증 기본 사항 (로컬 vs 원격)&quot;">​</a></h2><ul><li><strong>Localhost</strong>: <code>http://127.0.0.1:18789/</code>를 여십시오.</li><li><strong>공유 비밀 토큰 소스</strong>: <code>gateway.auth.token</code> (또는 <code>OPENCLAW_GATEWAY_TOKEN</code>); <code>openclaw dashboard</code>는 일회성 부트스트랩을 위해 URL 프래그먼트를 통해 전달할 수 있으며 Control UI는 현재 브라우저 탭 세션과 선택된 게이트웨이 URL에 대해 sessionStorage에 유지합니다.</li><li><code>gateway.auth.token</code>이 SecretRef로 관리되는 경우 <code>openclaw dashboard</code>는 설계상 토큰화되지 않은 URL을 인쇄/복사/열기합니다. 이는 셸 로그, 클립보드 기록 또는 브라우저 실행 인수에 외부 관리 토큰이 노출되는 것을 방지합니다.</li><li><strong>공유 비밀 비밀번호</strong>: 구성된 <code>gateway.auth.password</code> (또는 <code>OPENCLAW_GATEWAY_PASSWORD</code>)를 사용하십시오. 대시보드는 리로드 시 비밀번호를 유지하지 않습니다.</li><li><strong>아이덴티티 포함 모드</strong>: <code>gateway.auth.allowTailscale: true</code>인 경우 Tailscale Serve는 아이덴티티 헤더를 통해 Control UI/WebSocket 인증을 충족할 수 있으며, 비루프백 아이덴티티 인식 역방향 프록시는 <code>gateway.auth.mode: &quot;trusted-proxy&quot;</code>를 충족할 수 있습니다. 이러한 모드에서 대시보드는 WebSocket을 위해 붙여넣은 공유 비밀이 필요하지 않습니다.</li><li><strong>localhost가 아닌 경우</strong>: Tailscale Serve, 비루프백 공유 비밀 바인드, <code>gateway.auth.mode: &quot;trusted-proxy&quot;</code>를 사용하는 비루프백 아이덴티티 인식 역방향 프록시, 또는 SSH 터널을 사용하십시오. <a href="/openclaw-docs-ko/web">웹 인터페이스</a>를 참조하십시오.</li></ul><p><a id="if-you-see-unauthorized-1008"></a></p><h2 id="unauthorized-1008이-표시되는-경우" tabindex="-1">&quot;unauthorized&quot; / 1008이 표시되는 경우 <a class="header-anchor" href="#unauthorized-1008이-표시되는-경우" aria-label="Permalink to &quot;&quot;unauthorized&quot; / 1008이 표시되는 경우&quot;">​</a></h2><ul><li>게이트웨이에 도달할 수 있는지 확인하십시오 (로컬: <code>openclaw status</code>; 원격: SSH 터널 <code>ssh -N -L 18789:127.0.0.1:18789 user@host</code> 후 <code>http://127.0.0.1:18789/</code> 열기).</li><li><code>AUTH_TOKEN_MISMATCH</code>의 경우 게이트웨이가 재시도 힌트를 반환할 때 클라이언트는 캐시된 기기 토큰으로 한 번 신뢰할 수 있는 재시도를 할 수 있습니다. 그 후 인증이 계속 실패하면 토큰 드리프트를 수동으로 해결하십시오.</li><li>토큰 드리프트 수리 단계는 <a href="/openclaw-docs-ko/cli/devices#token-drift-recovery-checklist">토큰 드리프트 복구 체크리스트</a>를 따르십시오.</li><li>게이트웨이 호스트에서 공유 비밀을 가져오거나 제공하십시오: <ul><li>토큰: <code>openclaw config get gateway.auth.token</code></li><li>비밀번호: 구성된 <code>gateway.auth.password</code> 또는 <code>OPENCLAW_GATEWAY_PASSWORD</code> 해결</li><li>SecretRef로 관리되는 토큰: 외부 비밀 프로바이더를 해결하거나 이 셸에서 <code>OPENCLAW_GATEWAY_TOKEN</code>을 내보낸 후 <code>openclaw dashboard</code> 다시 실행</li><li>공유 비밀이 구성되지 않은 경우: <code>openclaw doctor --generate-gateway-token</code></li></ul></li><li>대시보드 설정에서 토큰 또는 비밀번호를 인증 필드에 붙여넣은 후 연결하십시오.</li><li>UI 언어 선택기는 <strong>개요 -&gt; 게이트웨이 액세스 -&gt; 언어</strong>에 있습니다. 모양 섹션이 아닌 액세스 카드의 일부입니다.</li></ul>',17)])])}const g=o(c,[["render",r]]);export{p as __pageData,g as default};
